class UserProfile{UserProfile({required this.id,required this.nickname,required this.votesCount,required this.submittedMemesCount,required this.status,this.createdAt});final String id,nickname,status;final int votesCount,submittedMemesCount;final String? createdAt;factory UserProfile.fromJson(Map<String,Object?> j)=>UserProfile(id:j['id'].toString(),nickname:j['nickname'].toString(),votesCount:(j['votesCount'] as num).toInt(),submittedMemesCount:(j['submittedMemesCount'] as num).toInt(),status:j['status'].toString(),createdAt:j['createdAt']?.toString());}
class MemeItem{MemeItem({required this.id,required this.title,required this.imageUrl,required this.rating,this.wins=0,this.losses=0,this.position});final String id,title,imageUrl;final int rating;final int wins,losses;final int? position;factory MemeItem.fromJson(Map<String,Object?> j)=>MemeItem(id:(j['id']??j['memeId']).toString(),title:j['title'].toString(),imageUrl:(j['contentUrl']??j['imageUrl']??'').toString(),rating:(j['rating'] as num).toInt(),wins:((j['wins']??0)as num).toInt(),losses:((j['losses']??0)as num).toInt(),position:j['position']==null?null:(j['position']as num).toInt());}
class Battle{Battle(this.battleId,this.left,this.right);final String battleId;final MemeItem left,right;factory Battle.fromJson(Map<String,Object?> j)=>Battle(j['battleId'].toString(),MemeItem.fromJson(j['left'] as Map<String,Object?>),MemeItem.fromJson(j['right'] as Map<String,Object?>));}
String statusLabel(String s)=>switch(s){'NEWBIE'=>'Новичок','SCOUT'=>'Мемный скаут','MEME_LORD'=>'Мемный лорд',_=>s};String periodCode(int i)=>['DAY','WEEK','ALL_TIME'][i];String? validateNickname(String v){final t=v.trim();if(t.length<3||t.length>30)return 'Ник должен быть от 3 до 30 символов';if(!RegExp(r'^[A-Za-zА-Яа-я0-9_ -]+$').hasMatch(t))return 'Используйте буквы, цифры, пробел, _ или -';return null;}
